const body = $input.first().json.body || {};
const complaintId     = parseInt(body.complaintId);
const newClosureDate  = (body.newClosureDate || '');
const escalationLevel = parseInt(body.escalationLevel || 1);
const delayMain       = body.delayMain  || '';
const delaySub        = body.delaySub   || '';
const extraRemarks    = body.remarks    || '';
const uid             = parseInt(body.uid || 1);
const agentName       = esc(body.agentName || '');

if (!complaintId || !newClosureDate) return [{ json: { success: false, error: 'complaintId and newClosureDate required' } }];

const esc = v => (v || '').toString().replace(/'/g, "''");

const parts = [];
if (delayMain) parts.push('Delay: ' + delayMain + (delaySub ? ' - ' + delaySub : ''));
if (extraRemarks) parts.push(extraRemarks);
if (!parts.length) parts.push('EDC Extended');

const remarksStr = esc(parts.join(' | '));

const insertLog = `INSERT INTO vmm_complaintlogs (complaintid, remarks, status, uid, agentname, created, is_deleted) VALUES (${complaintId}, '${remarksStr}', 'Escalated', ${uid}, '${agentName}', NOW(), 'No')`;

const insertEsc = `INSERT INTO vmm_vendorescalations (complaintid, escalationlevel, ticketno, closuredate, uid, created, is_deleted) VALUES (${complaintId}, ${escalationLevel}, '', '${esc(newClosureDate)}', ${uid}, NOW(), 'No')`;

return [{ json: { insertLog, insertEsc, complaintId, newClosureDate, escalationLevel } }];
